parameters.jsCode:
for (const item of items) {
  const body = $('Web Contact Form').first().json.body || {};
  const date = body.date;
  const time = body.time;
  const meetingDurationMinutes = $input.first().json.meeting_time || 30; // fallback to 30 if undefined

  let bookingStart = null;
  let bookingEnd = null;
  let durationTime = null;

  if (date && time) {
    const start = new Date(`${date}T${time}:00+06:00`);
    if (!isNaN(start)) {
      bookingStart = start.toISOString();
      bookingEnd = new Date(start.getTime() + meetingDurationMinutes * 60 * 1000).toISOString();
      durationTime = ((new Date(bookingEnd).getTime() - new Date(bookingStart).getTime()) / (1000 * 60)) + " minutes";
    }
  }

  item.json = {
    client_name: body.name || null,
    client_email: body.email || null,
    client_messate: body.message || null,
    booking_date: date || null,
    booking_time: time || null,
    booking_start: bookingStart,
    booking_end: bookingEnd,
    duration_time: durationTime,
  };
}

return items;

